/**
 * Seed script: Inserts WASSCE/NECO syllabus-aligned lessons for SS1-SS3.
 *
 * Usage:
 *   npx tsx scripts/seed-lessons.ts
 *
 * Requires DATABASE_URL env var (loaded from .env or set in environment).
 */

import { neon } from '@neondatabase/serverless';

const sql = neon(process.env.DATABASE_URL!);

// ─── Syllabus data ───────────────────────────────────────────────────────────
// Each topic is mapped to the WAEC/NECO scheme of work for that class.

interface LessonDef {
  topic: string;
  body: string;
}

const COMMERCIAL = 'Commercial';
const SCIENCE   = 'Science';
const TECH      = 'Tech';
const ARTS      = 'Arts';

function departmentOf(subject: string): string {
  if (['Commerce','Accounting','Economics','Business Studies'].includes(subject)) return COMMERCIAL;
  if (['Biology','Chemistry','Physics','Mathematics'].includes(subject)) return SCIENCE;
  if (['Basic Technology','Computer Studies','Technical Drawing'].includes(subject)) return TECH;
  if (['English Language','Literature-in-English','Government','History','Christian Religious Studies'].includes(subject)) return ARTS;
  throw new Error(`Unknown subject: ${subject}`);
}

