// ─── Seed runner ─────────────────────────────────────────────────────────────

async function seed() {
  console.log('🌱 Seeding WAEC/NECO-aligned lessons...\n');

  const existing = await sql.query('SELECT COUNT(*) as count FROM lessons');
  const count = Number(existing[0]?.count ?? 0);
  if (count > 0) {
    console.log(`  ⚠️  ${count} lesson(s) already exist. Deleting old data...`);
    await sql.query('DELETE FROM flagged_qa');
    await sql.query('DELETE FROM lesson_progress');
    await sql.query('DELETE FROM artifact_content');
    await sql.query('DELETE FROM lessons');
    console.log('  ✅ Cleared.\n');
  }

  const allData: Record<string, Record<string, LessonDef[]>> = { SS1, SS2, SS3 };
  let total = 0;

  for (const level of ['SS1', 'SS2', 'SS3'] as const) {
    const subjects = allData[level];
    for (const [subject, lessons] of Object.entries(subjects)) {
      const department = departmentOf(subject);
      for (const lesson of lessons) {
        const title = `${level} ${subject} — ${lesson.topic}`;
        // Build description: plain text excerpt from body
        const desc = lesson.body
          .replace(/<[^>]+>/g, '')
          .substring(0, 160)
          .replace(/\s+/g, ' ')
          .trim() + '...';

        const content = `<h2 class="text-xl font-bold mb-4">${lesson.topic}</h2>\n<div class="space-y-4 text-gray-700 leading-relaxed">\n${lesson.body}\n</div>\n`;

        await sql.query(
          `INSERT INTO lessons (title, description, content, class_level, department)
           VALUES ($1, $2, $3, $4, $5)`,
          [title, desc, content, level, department]
        );
        total++;
      }
    }
    console.log(`  📚 ${level}: inserted ${Object.values(subjects).flat().length} lessons`);
  }

  console.log(`\n✅ Done! ${total} WAEC/NECO-aligned lessons inserted.`);
}

seed().catch((err) => {
  console.error('❌ Seed failed:', err);
  process.exit(1);
});
